script:
frappe.ui.form.on('Address', {
    refresh: function(frm) {
        if (frm.is_new()) {
            if (!frm.doc.country) {
                frm.set_value('country', 'Ukraine');
            }
            if (!frm.doc.city) {
                frm.set_value('city', 'Кривий Ріг');
            }
            if (!frm.doc.state) {
                frm.set_value('state', 'Дніпропетровська');
            }
        }
    }
});
